{
  "verdict": "reject",
  "conceptual_groups": [
    {
      "id": "group-1",
      "summary": "Artifact lifecycle is not mechanically complete: canonical outputs are described ambiguously and do not match the required on-disk role package paths.",
      "severity": "blocking",
      "findings": [
        {
          "id": "f1",
          "description": "The self-check already reports four MISSING_REQUIRED_OUTPUT failures because <outputs> names canonical artifacts as <slug>-based filenames instead of the required canonical paths under tools/agent-role-builder/role/.",
          "source_section": "<outputs> / Self-check issues"
        },
        {
          "id": "f2",
          "description": "Step 2 writes draft artifacts into drafts/, and Step 5 says 'promote to canonical directory', but the canonical destination is never explicitly stated in the role markdown. The promotion target therefore has to be inferred.",
          "source_section": "<steps>"
        },
        {
          "id": "f3",
          "description": "The contract summary package_files block also omits the canonical directory prefix, creating a second inconsistent representation of artifact locations across markdown, contract, and filesystem reality.",
          "source_section": "Contract summary.package_files"
        },
        {
          "id": "f4",
          "description": "Completion criteria are generic and not terminal-state-specific. 'Decision log updated (on freeze)' does not fully define artifact obligations for pushback, blocked, or resume_required, and it leaves update/fix history preservation underspecified outside the happy path.",
          "source_section": "<completion> / <guardrails> / <steps>"
        }
      ],
      "redesign_guidance": "State the canonical role package directory explicitly and reference full tool-relative paths for every canonical artifact. Separate canonical artifacts from run-scoped evidence consistently, and define completion requirements per terminal state: frozen, pushback, blocked, and resume_required."
    },
    {
      "id": "group-2",
      "summary": "Authority is not expressed as a clean precedence chain, and the draft mixes operative authority with reference documents and request-time settings.",
      "severity": "major",
      "findings": [
        {
          "id": "f1",
          "description": "The draft says 'Reports to: COO controller' but then lists docs/v0/architecture.md and docs/VISION.md under 'Subordinate to', which treats static documents like live superiors instead of reference authority. That makes the authority model unclear.",
          "source_section": "<authority>"
        },
        {
          "id": "f2",
          "description": "The package never states what wins if the controller, request, contract, and referenced docs disagree. For a governance tool, missing precedence is a material defect rather than wording noise.",
          "source_section": "<authority> / Contract summary"
        },
        {
          "id": "f3",
          "description": "The contract embeds runtime knobs such as execution_mode, watchdog_timeout_seconds, max_launch_attempts, and allow_provider_fallback as if they were durable role semantics. These read as invocation config, not stable role truth, and no authority basis is given for them here.",
          "source_section": "Contract summary.runtime"
        }
      ],
      "redesign_guidance": "Rewrite authority as an explicit precedence chain. Separate operative governance from reference evidence, and move request-specific runtime settings out of the durable role definition unless a governing source explicitly requires them."
    },
    {
      "id": "group-3",
      "summary": "Several governance behaviors are asserted without enough source-backed precision, which risks inventing semantics in the role package.",
      "severity": "major",
      "findings": [
        {
          "id": "f1",
          "description": "The role requires one live Codex leader and at least one live Codex+Claude reviewer pair, but the draft does not clearly establish a binding source for the Codex-only leader requirement. The reviewer-pair requirement is grounded; the leader-provider requirement is not made equally authoritative here.",
          "source_section": "<role> / <inputs> / <guardrails>"
        },
        {
          "id": "f2",
          "description": "Step 4 says 'Arbitrate after 2+ consecutive splits' without defining actor, evidence, severity limits, or outcome semantics. That diverges from the approved review-process architecture, which limits arbitration to minor items only.",
          "source_section": "<steps>"
        },
        {
          "id": "f3",
          "description": "The contract intent says 'Resume and finalize the agent-role-builder self-role using improved review process...', which is bootstrap-run context rather than durable role intent. That leaks a one-off run into long-lived package semantics.",
          "source_section": "Contract summary.intent"
        }
      ],
      "redesign_guidance": "Keep only source-backed governance mechanics in the role. If a behavior is runtime policy or bootstrap context, put it in request/config or decision log evidence instead of the durable role contract."
    },
    {
      "id": "group-4",
      "summary": "Scope boundaries are directionally correct but not fully exact because the exclusion list contains duplicated semantics.",
      "severity": "minor",
      "findings": [
        {
          "id": "f1",
          "description": "'Application workflow creation' appears twice in Not in scope, once bare and once clarified parenthetically. The clarification is useful, but the duplicate phrasing weakens the exactness expected of a governed role.",
          "source_section": "<scope>"
        }
      ],
      "redesign_guidance": "Deduplicate the exclusion list and keep one canonical phrasing per out-of-scope concept."
    }
  ],
  "residual_risks": [
    "If runtime/provider specifics remain embedded in the role package, future controller or roster changes will force unnecessary role rewrites and create false governance drift.",
    "If canonical and run-scoped artifact paths remain implicit, promotion, resume, and audit flows can write or validate the wrong files even when the draft looks structurally complete."
  ],
  "strengths": [
    "The required XML-tagged structure is present, and Step 3 explicitly enumerates the required tag set.",
    "High-level ownership boundaries are mostly sound: tool creation is excluded, and the role stays focused on role-package governance.",
    "Context-gathering order is sensible: request validation, source verification, baseline loading, and resume evidence are sequenced coherently."
  ]
